module top_module(
    input                       clk,

    input       [widthad-1:0]   wraddress,
    input                       wren,
    input       [width-1:0]     data,

    input       [widthad-1:0]   rdaddress,
    output reg  [width-1:0]     q
);parameter width     = 1;
parameter widthad   = 1;

reg [width-1:0] mem [(2**widthad)-1:0];

always @(posedge clk) begin
  if(wren) mem[wraddress] <= data ;
  end

  always @(posedge clk) begin
  q <= mem[rdaddress] ;
  end

endmodule
